INSERT INTO mcqs (question, option_a, option_b, option_c, option_d, correct_answer, category, difficulty, explanation) VALUES
('What is an Operating System?', 'A program that runs on a computer', 'Software that manages hardware and software resources', 'A type of file system', 'Part of the CPU', 'Software that manages hardware and software resources', 'Operating System', 'Easy', 'An OS is system software that acts as an intermediary between the user and the computer hardware.'),
('Which of the following is a real-time operating system?', 'Windows', 'Linux', 'VxWorks', 'macOS', 'VxWorks', 'Operating System', 'Medium', 'VxWorks is a real-time operating system used in embedded systems.'),
('What is the main function of a kernel?', 'Managing files', 'Running user applications', 'Managing memory and hardware', 'Displaying graphics', 'Managing memory and hardware', 'Operating System', 'Medium', 'The kernel is the core of the OS that manages all system resources.'),
('What is virtual memory?', 'Memory on a USB drive', 'Using disk space as if it were RAM', 'Memory used by virtual machines only', 'Temporary memory', 'Using disk space as if it were RAM', 'Operating System', 'Hard', 'Virtual memory allows the system to use disk storage as an extension of RAM.'),
('What is a semaphore used for?', 'File storage', 'Process synchronization', 'Network communication', 'Display output', 'Process synchronization', 'Operating System', 'Hard', 'Semaphores are synchronization primitives used to control access to shared resources.'),
('What does TCP stand for?', 'Transfer Control Protocol', 'Transmission Control Protocol', 'Transfer Communication Protocol', 'Transmission Communication Protocol', 'Transmission Control Protocol', 'Computer Networks', 'Easy', 'TCP (Transmission Control Protocol) is a core protocol of the Internet Protocol Suite.'),
('Which layer of the OSI model is responsible for routing?', 'Physical', 'Data Link', 'Network', 'Transport', 'Network', 'Computer Networks', 'Easy', 'The Network layer (Layer 3) handles routing of data packets.'),
('What is the difference between HTTP and HTTPS?', 'HTTPS is faster', 'HTTPS is secure with encryption', 'HTTP is more reliable', 'HTTPS cannot be used for forms', 'HTTPS is secure with encryption', 'Computer Networks', 'Medium', 'HTTPS uses SSL/TLS encryption to secure data transmission.'),
('What is the purpose of ARP?', 'File transfer', 'Map IP addresses to MAC addresses', 'Encrypt data', 'Route packets', 'Map IP addresses to MAC addresses', 'Computer Networks', 'Medium', 'Address Resolution Protocol (ARP) maps IP addresses to physical MAC addresses.'),
('What is bandwidth?', 'The physical width of cables', 'Maximum data transfer rate', 'The strength of a signal', 'The number of routers', 'Maximum data transfer rate', 'Computer Networks', 'Hard', 'Bandwidth is the maximum rate of data transfer across a network path.'),
('What is encapsulation in Java?', 'Combining methods into classes', 'Wrapping data and methods together', 'Hiding internal details of an object', 'All of the above', 'All of the above', 'Java', 'Easy', 'Encapsulation is bundling data and methods while hiding implementation details.'),
('Which keyword is used for inheritance in Java?', 'inherits', 'extends', 'implements', 'extends and implements', 'extends and implements', 'Java', 'Easy', 'The extends keyword is used for class inheritance, and implements for interface implementation.'),
('What is polymorphism?', 'Having multiple parents', 'One object having multiple forms', 'Using multiple methods', 'Creating objects dynamically', 'One object having multiple forms', 'Java', 'Medium', 'Polymorphism allows objects to take multiple forms through method overriding and overloading.'),
('What is the difference between ArrayList and LinkedList?', 'ArrayList is faster for insertion', 'LinkedList uses less memory', 'ArrayList uses array internally while LinkedList uses doubly linked list', 'They are identical', 'ArrayList uses array internally while LinkedList uses doubly linked list', 'Java', 'Medium', 'ArrayList provides fast random access while LinkedList is efficient for insertion/deletion.'),
('What is the purpose of the final keyword?', 'Mark variables as constant', 'Prevent class inheritance', 'Make method final', 'All of the above', 'All of the above', 'Java', 'Hard', 'The final keyword can be used on classes, methods, and variables to prevent modification.'),
('What is normalization in databases?', 'Making all data the same size', 'Organizing data to reduce redundancy', 'Compressing data', 'Encrypting data', 'Organizing data to reduce redundancy', 'DBMS', 'Easy', 'Normalization is a process to structure a database in order to reduce data redundancy.'),
('What are the types of keys in a database?', 'Primary and Secondary', 'Foreign and Foreign', 'Candidate and Primary', 'Primary, Foreign, and Unique', 'Primary, Foreign, and Unique', 'DBMS', 'Medium', 'Keys include Primary (unique identifier), Foreign (reference), Unique (distinct values), and Composite keys.'),
('What is ACID in databases?', 'A chemical compound', 'Atomicity, Consistency, Isolation, Durability', 'A type of join', 'An indexing method', 'Atomicity, Consistency, Isolation, Durability', 'DBMS', 'Medium', 'ACID properties ensure reliable database transactions.'),
('What is a transaction in database?', 'A sale or purchase', 'A sequence of operations treated as a single unit', 'A backup process', 'A query statement', 'A sequence of operations treated as a single unit', 'DBMS', 'Hard', 'A transaction is a logical unit of work that must be completed entirely or not at all.'),
('What is the difference between DELETE and DROP?', 'DELETE is faster', 'DROP removes table structure while DELETE removes rows', 'DELETE is permanent', 'No difference', 'DROP removes table structure while DELETE removes rows', 'DBMS', 'Hard', 'DELETE removes data rows while DROP removes the entire table structure.'),
('What is an abstract class in OOP?', 'A class that cannot be instantiated', 'A class with only abstract methods', 'A class that must be inherited', 'All of the above', 'A class that cannot be instantiated', 'OOP', 'Medium', 'An abstract class cannot be instantiated and must be inherited to be used.'),
('What is an interface in OOP?', 'A contract for a class to implement', 'A blueprint for creating objects', 'A way to achieve multiple inheritance', 'All of the above', 'All of the above', 'OOP', 'Medium', 'An interface defines a contract that implementing classes must follow.'),
('What is method overriding?', 'Calling the same method name', 'Providing specific implementation in subclass', 'Using same method name with different parameters', 'Inheriting multiple classes', 'Providing specific implementation in subclass', 'OOP', 'Easy', 'Method overriding allows a subclass to provide a specific implementation of a method from parent class.'),
('What is the difference between composition and inheritance?', 'Composition is faster', 'Inheritance uses "is-a" while composition uses "has-a"', 'Composition is preferred', 'Inheritance is always better', 'Inheritance uses "is-a" while composition uses "has-a"', 'OOP', 'Hard', 'Composition (has-a) and inheritance (is-a) are two ways to achieve code reusability.'),
('What is a constructor?', 'A method that destroys objects', 'A special method for initializing objects', 'A method that returns values', 'A method that is always abstract', 'A special method for initializing objects', 'OOP', 'Easy', 'A constructor is a special method called when an object is created to initialize its state.'),
('What does SELECT * mean in SQL?', 'Select a specific row', 'Select all columns from a table', 'Select a specific column', 'Select multiple tables', 'Select all columns from a table', 'SQL', 'Easy', 'The asterisk (*) in SELECT * means select all columns.'),
('What is a JOIN in SQL?', 'Combining strings', 'Combining rows from multiple tables', 'Merging databases', 'Adding new columns', 'Combining rows from multiple tables', 'SQL', 'Easy', 'A JOIN combines rows from two or more tables based on related columns.'),
('What is the difference between INNER JOIN and LEFT JOIN?', 'INNER JOIN is faster', 'INNER JOIN returns only matching rows while LEFT JOIN includes all from left table', 'They are the same', 'LEFT JOIN is always better', 'INNER JOIN returns only matching rows while LEFT JOIN includes all from left table', 'SQL', 'Medium', 'INNER JOIN returns only rows that match in both tables, while LEFT JOIN includes all rows from the left table.'),
('What does GROUP BY do?', 'Groups data into files', 'Groups rows that have the same values', 'Arranges data alphabetically', 'Filters data', 'Groups rows that have the same values', 'SQL', 'Medium', 'GROUP BY clause divides rows into groups based on specified columns.'),
('What is the purpose of HAVING clause?', 'Same as WHERE', 'Filters groups after aggregation', 'Orders results', 'Limits output', 'Filters groups after aggregation', 'SQL', 'Hard', 'HAVING filters groups created by GROUP BY, while WHERE filters individual rows.');
INSERT INTO coding_questions (title, topic, difficulty, description, platform, platform_url, problem_number) VALUES
('Two Sum', 'Arrays', 'Easy', 'Given an array of integers nums and an integer target, return the indices of the two numbers that add up to target.', 'LeetCode', 'https://leetcode.com', '1'),
('Reverse String', 'Strings', 'Easy', 'Write a function that reverses a string.', 'LeetCode', 'https://leetcode.com', '344'),
('Linked List Cycle', 'Linked List', 'Easy', 'Given a linked list, determine if it has a cycle in it.', 'LeetCode', 'https://leetcode.com', '141'),
('Valid Parentheses', 'Stack', 'Easy', 'Given a string s containing just the characters "(", ")", "{", "}", "[" and "]", determine if the input string is valid.', 'LeetCode', 'https://leetcode.com', '20'),
('Implement Queue using Stacks', 'Queue', 'Easy', 'Implement a first in first out queue using two stacks.', 'LeetCode', 'https://leetcode.com', '232'),
('Binary Tree Level Order Traversal', 'Binary Tree', 'Medium', 'Given the root of a binary tree, return the level order traversal of its nodes values.', 'LeetCode', 'https://leetcode.com', '102'),
('Validate Binary Search Tree', 'BST', 'Medium', 'Given the root of a binary tree, determine if it is a valid binary search tree.', 'LeetCode', 'https://leetcode.com', '98'),
('Kth Largest Element in an Array', 'Heap', 'Medium', 'Find the kth largest element in an unsorted array.', 'LeetCode', 'https://leetcode.com', '215'),
('Number of Islands', 'Graph', 'Medium', 'Given an m x n 2D binary grid grid which represents a map of "1"s (land) and "0"s (water), return the number of islands.', 'LeetCode', 'https://leetcode.com', '200'),
('Permutations', 'Recursion', 'Medium', 'Given an array nums of distinct integers, return all the possible permutations.', 'LeetCode', 'https://leetcode.com', '46'),
('Palindrome Partitioning', 'Backtracking', 'Medium', 'Given a string s, partition s such that every substring of the partition is a palindrome.', 'LeetCode', 'https://leetcode.com', '131'),
('Minimum Window Substring', 'Sliding Window', 'Hard', 'Given two strings s and t of lengths m and n respectively, return the minimum window substring of s such that every character in t is included in the window.', 'LeetCode', 'https://leetcode.com', '76'),
('Longest Increasing Subsequence', 'Dynamic Programming', 'Medium', 'Given an integer array nums, return the length of the longest strictly increasing subsequence.', 'LeetCode', 'https://leetcode.com', '300'),
('Binary Search', 'Searching', 'Easy', 'Given a sorted array of integers and a target value, find the index of the target if it is in the array.', 'LeetCode', 'https://leetcode.com', '704'),
('Merge Sort', 'Sorting', 'Medium', 'Sort an array using merge sort algorithm.', 'LeetCode', 'https://leetcode.com', '912'),
('Jump Game', 'Greedy', 'Medium', 'You are given an integer array nums. You are initially positioned at the arrays first index and each element in the array represents your maximum jump length from that position.', 'LeetCode', 'https://leetcode.com', '55'),
('Majority Element', 'Arrays', 'Easy', 'Given an array nums of size n, return the majority element which appears more than n / 2 times.', 'LeetCode', 'https://leetcode.com', '169'),
('Longest Substring Without Repeating Characters', 'Strings', 'Medium', 'Given a string s, find the length of the longest substring without repeating characters.', 'LeetCode', 'https://leetcode.com', '3'),
('Merge K Sorted Lists', 'Linked List', 'Hard', 'You are given an array of k linked-lists lists, each linked-list is sorted in ascending order. Merge all the linked-lists into one sorted linked-list and return it.', 'LeetCode', 'https://leetcode.com', '23'),
('Largest Rectangle in Histogram', 'Stack', 'Hard', 'Given an array of integers heights representing the histogram, find the area of the largest rectangle in the histogram.', 'LeetCode', 'https://leetcode.com', '84'),
('Design Circular Queue', 'Queue', 'Medium', 'Design your implementation of the circular queue.', 'LeetCode', 'https://leetcode.com', '622'),
('Lowest Common Ancestor of a Binary Tree', 'Binary Tree', 'Medium', 'Given a binary tree, find the lowest common ancestor of two given nodes in the tree.', 'LeetCode', 'https://leetcode.com', '236'),
('Serialize and Deserialize Binary Tree', 'BST', 'Hard', 'Serializes a tree to a single string and deserializes the string back to the original tree structure.', 'LeetCode', 'https://leetcode.com', '297'),
('Median of Two Sorted Arrays', 'Heap', 'Hard', 'Given two sorted arrays nums1 and nums2 of size m and n respectively, return the median of the two sorted arrays.', 'LeetCode', 'https://leetcode.com', '4'),
('Course Schedule', 'Graph', 'Medium', 'There are a total of numCourses courses you have to take, labeled from 0 to numCourses - 1. Determine if you can finish all courses.', 'LeetCode', 'https://leetcode.com', '207'),
('Word Ladder', 'Recursion', 'Medium', 'Given two words, beginWord and endWord, and a dictionary wordList, return all the shortest transformation sequences from beginWord to endWord.', 'LeetCode', 'https://leetcode.com', '126'),
('Word Search II', 'Backtracking', 'Hard', 'Given an m x n board of character board and a list of strings words, return all words on the board.', 'LeetCode', 'https://leetcode.com', '212'),
('Best Time to Buy and Sell Stock', 'Sliding Window', 'Easy', 'You are given an array prices where prices[i] is the price of a given stock on the ith day. Find the maximum profit.', 'LeetCode', 'https://leetcode.com', '121'),
('Coin Change', 'Dynamic Programming', 'Medium', 'You are given an integer array coins representing coins of different denominations and an integer amount. Return the fewest number of coins needed to make that amount.', 'LeetCode', 'https://leetcode.com', '322'),
('Find Peak Element', 'Searching', 'Medium', 'A peak element is an element that is strictly greater than its neighbors. Find a peak element and return its index.', 'LeetCode', 'https://leetcode.com', '162'),
('Top K Frequent Elements', 'Sorting', 'Medium', 'Given an integer array nums and an integer k, return the k most frequent elements.', 'LeetCode', 'https://leetcode.com', '347');
